// db/migrate.withForeignKeysOff.test.ts
import { describe, it, expect, beforeEach, afterEach } from "vitest";
import Database from "better-sqlite3";

// ---------------------------------------------------------------------------
// Inline the system under test so the test is self-contained and does NOT
// depend on the real resolvedPath / schema. We reproduce only the behaviour
// that matters: the pragma-sandwich around a transaction that does a
// table-rebuild (DROP old table with FK children).
// ---------------------------------------------------------------------------

function makeDb() {
    const sqlite = new Database(":memory:");
    sqlite.pragma("journal_mode = WAL");
    sqlite.pragma("foreign_keys = ON");

    // ---- schema ------------------------------------------------------------
    sqlite.exec(`
        CREATE TABLE tasks (
            id   TEXT PRIMARY KEY,
            name TEXT NOT NULL,
            session_id TEXT NOT NULL          -- will become nullable in "migration"
        );

        CREATE TABLE task_events (
            id      TEXT PRIMARY KEY,
            task_id TEXT NOT NULL
                REFERENCES tasks(id) ON DELETE CASCADE
        );
    `);

    // ---- helper (mirrors the exported withForeignKeysOff) ------------------
    function withForeignKeysOff(fn: () => void): void {
        sqlite.pragma("foreign_keys = OFF");
        try {
            fn();
        } finally {
            sqlite.pragma("foreign_keys = ON");
        }
    }

    // ---- simulated migrator: runs fn() inside a transaction ----------------
    // This mirrors what drizzle's migrator does: wrap in BEGIN/COMMIT.
    function simulateMigrator(migrationSql: string): void {
        // The PRAGMA inside the SQL is a no-op; what matters is the
        // connection-level state set by withForeignKeysOff.
        sqlite.transaction(() => {
            sqlite.exec(migrationSql);
        })();
    }

    return { sqlite, withForeignKeysOff, simulateMigrator };
}

// The migration SQL drizzle-kit generates for making session_id nullable.
// The PRAGMA foreign_keys=OFF inside is the one that SQLite ignores in a txn.
const MIGRATION_0005 = `
    PRAGMA foreign_keys=OFF;
    CREATE TABLE \`__new_tasks\` (
        \`id\`         TEXT PRIMARY KEY,
        \`name\`       TEXT NOT NULL,
        \`session_id\` TEXT            -- now nullable
    );
    INSERT INTO \`__new_tasks\` (\`id\`, \`name\`, \`session_id\`)
        SELECT \`id\`, \`name\`, \`session_id\` FROM \`tasks\`;
    DROP TABLE \`tasks\`;
    ALTER TABLE \`__new_tasks\` RENAME TO \`tasks\`;
    PRAGMA foreign_keys=ON;
`;

describe("withForeignKeysOff / migration table-rebuild", () => {
    let ctx: ReturnType<typeof makeDb>;

    beforeEach(() => {
        ctx = makeDb();
        // Seed: 2 tasks, each with 2 events
        ctx.sqlite.exec(`
            INSERT INTO tasks VALUES ('t1', 'Task 1', 's1');
            INSERT INTO tasks VALUES ('t2', 'Task 2', 's1');
            INSERT INTO task_events VALUES ('e1', 't1');
            INSERT INTO task_events VALUES ('e2', 't1');
            INSERT INTO task_events VALUES ('e3', 't2');
            INSERT INTO task_events VALUES ('e4', 't2');
        `);
    });

    afterEach(() => {
        ctx.sqlite.close();
    });

    it("BEFORE FIX (regression guard): DROP TABLE inside a transaction wipes task_events when FK is ON", () => {
        // Demonstrates the bug: run the migration WITHOUT the pragma sandwich.
        // FK is ON at connection level; PRAGMA inside txn is ignored → cascade fires.
        expect(() => {
            ctx.simulateMigrator(MIGRATION_0005);
        }).not.toThrow(); // SQLite doesn't error; it just silently cascades

        const remaining = ctx.sqlite
            .prepare("SELECT COUNT(*) as n FROM task_events")
            .get() as { n: number };

        // BUG: all 4 rows are gone because CASCADE fired on DROP TABLE tasks
        expect(remaining.n).toBe(0); // this passes (confirms the bug exists)
    });

    it("AFTER FIX: withForeignKeysOff preserves task_events rows during table-rebuild", () => {
        // Rebuild the db fresh so this test is independent
        const { sqlite, withForeignKeysOff, simulateMigrator } = makeDb();
        sqlite.exec(`
            INSERT INTO tasks VALUES ('t1', 'Task 1', 's1');
            INSERT INTO tasks VALUES ('t2', 'Task 2', 's1');
            INSERT INTO task_events VALUES ('e1', 't1');
            INSERT INTO task_events VALUES ('e2', 't1');
            INSERT INTO task_events VALUES ('e3', 't2');
            INSERT INTO task_events VALUES ('e4', 't2');
        `);

        // THE FIX: disable FK at connection level BEFORE migrator opens its txn
        withForeignKeysOff(() => {
            simulateMigrator(MIGRATION_0005);
        });

        const remaining = sqlite
            .prepare("SELECT COUNT(*) as n FROM task_events")
            .get() as { n: number };

        // All 4 child rows must survive
        expect(remaining.n).toBe(4);

        // FK enforcement must be re-enabled after the sandwich
        const fkState = sqlite.pragma("foreign_keys", { simple: true });
        expect(fkState).toBe(1);

        // tasks table must exist with correct nullable column and all rows
        const tasks = sqlite.prepare("SELECT COUNT(*) as n FROM tasks").get() as { n: number };
        expect(tasks.n).toBe(2);

        sqlite.close();
    });

    it("withForeignKeysOff re-enables FK even when fn() throws", () => {
        const { sqlite, withForeignKeysOff } = makeDb();

        expect(() => {
            withForeignKeysOff(() => {
                throw new Error("migration exploded");
            });
        }).toThrow("migration exploded");

        // INVARIANT: FK must be back ON despite the throw
        const fkState = sqlite.pragma("foreign_keys", { simple: true });
        expect(fkState).toBe(1);

        sqlite.close();
    });
