## Fix Implementation

**File: `client.ts`**
```typescript
import Database from 'better-sqlite3';
import { drizzle } from 'drizzle-orm/better-sqlite3';

const sqlite = new Database(process.env.DATABASE_URL || ':memory:');
// Set foreign_keys pragma BEFORE any operations
sqlite.pragma('foreign_keys = ON');

export const db = drizzle(sqlite);

// Export the sqlite handle so migrator can use the same connection
export const getRawDatabase = () => sqlite;
