import { migrate } from 'drizzle-orm/better-sqlite3/migrator';
import { db, getRawDatabase } from './client';

export async function runMigrations() {
  const sqlite = getRawDatabase();

  // Ensure foreign keys are ON before and after migrations
  sqlite.pragma('foreign_keys = ON');

  // Run migrations with explicit transaction control
  // to ensure FK pragma state is preserved
  try {
    migrate(db, { migrationsFolder: './drizzle' });
    // Re-assert foreign_keys after migrations complete
    sqlite.pragma('foreign_keys = ON');
  } catch (error) {
    // On error, ensure FKs are re-enabled
    sqlite.pragma('foreign_keys = ON');
    throw error;
  }
}
